# ROBUSTNESS PHASE L — Codegen output fidelity
# Manually written, not generated by testgen.py. Do not delete.
#
# Runs codegen.py (not --dry-run) on a controlled YAML and asserts that
# the generated C files contain the correct numeric values, identifiers,
# and structural patterns derived from that YAML.
#
# What this catches that Phase A does not:
#   A proves files exist and compile.
#   L proves the *content* is correct — wrong DID IDs, wrong timing
#   constants, wrong session gates, wrong severity bytes all pass Phase A
#   and fail here.
#
# Run: pytest test_robustness_L_codegen_output_fidelity.py -v
from __future__ import annotations

import atexit
import os
import shutil
import subprocess
import sys
import tempfile
import textwrap
from pathlib import Path

import pytest

EDS_ROOT = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..", "..", ".."))
CODEGEN  = os.path.join(EDS_ROOT, "tools", "codegen.py")

# ── Controlled test YAML ──────────────────────────────────────────────────────
#
# Values are chosen to be distinct from the basic_ecu example so that a
# stale file from a different run cannot mask a regression.
#   p2 = 50 ms  (not 25)    DID count = 2 (not 5)    DTC count = 1 (not 2)
#   ECU name = "TestECU"    version   = "2.0.0"
#
_YAML = textwrap.dedent("""\
    schema_version: 1
    metadata:
      ecu_name: "TestECU"
      version: "2.0.0"
    timing:
      p2_server_max_ms: 50
      p2_star_server_max_ms: 5000
      s3_server_timeout_ms: 5000
    dids:
      - id: "0xF190"
        name: "Vehicle Identification Number"
        access: [read]
        min_session: "default"
        read_security_level:  0
        write_security_level: 0
        data_length: 17
      - id: "0xF187"
        name: "Spare Part Number"
        access: [read, write]
        min_session: "extended"
        read_security_level:  0
        write_security_level: 1
        data_length: 11
    dtcs:
      - code: "0xC00100"
        description: "CAN bus loss"
        severity: "check_at_next_halt"
    routines:
      - id: "0xFF00"
        name: "SelfTest"
        min_session: "extended"
        security_level: 0
        support: ["start", "results"]
      - id: "0xFF01"
        name: "EraseNVM"
        min_session: "programming"
        security_level: 1
        support: ["start"]
""")

# ── Templates availability check ──────────────────────────────────────────────
#
# Jinja2 templates live in EDS-toolchain (commercial-only) and are linked via
# symlink at tools/templates → ../../../EDS-toolchain/tools/templates.
# On the public CI runner the target does not exist, so the entire module is
# skipped via pytestmark rather than failing with "template directory not found".

_TEMPLATES_OK = os.path.isdir(os.path.join(EDS_ROOT, "tools", "templates"))

pytestmark = pytest.mark.skipif(
    not _TEMPLATES_OK,
    reason="Jinja2 templates not present (commercial-only, not in public repo)"
)

# ── Generate once at module import ────────────────────────────────────────────

_TMPDIR = tempfile.mkdtemp(prefix="eds_phase_l_")
_OUT    = os.path.join(_TMPDIR, "out")
os.makedirs(_OUT)
_CFG    = os.path.join(_TMPDIR, "config.yaml")
with open(_CFG, "w") as f:
    f.write(_YAML)

if _TEMPLATES_OK:
    _proc = subprocess.run(
        [sys.executable, CODEGEN, "--config", _CFG, "--out", _OUT],
        capture_output=True, text=True,
    )
    _RC  = _proc.returncode
    _LOG = _proc.stdout + _proc.stderr
else:
    _RC  = -1
    _LOG = ""

atexit.register(shutil.rmtree, _TMPDIR, ignore_errors=True)

_EXPECTED_FILES = (
    "generated_config.h",
    "did_handlers.h",
    "did_handlers.c",
    "routine_handlers.c",
    "uds_init.c",
)


def _read(filename: str) -> str:
    return Path(_OUT, filename).read_text()


# ── Helpers ───────────────────────────────────────────────────────────────────

def _assert_define(content: str, macro: str, value: str) -> None:
    for line in content.splitlines():
        if macro in line and value in line:
            return
    raise AssertionError(
        f"Expected '#define {macro}' containing '{value}'.\n"
        f"Searched in:\n{content[:2000]}"
    )


# ── Class 1: Sanity ───────────────────────────────────────────────────────────

class TestSanity:
    def test_codegen_exits_0(self):
        assert _RC == 0, f"codegen failed (exit {_RC}):\n{_LOG}"

    def test_all_expected_files_generated(self):
        missing = [f for f in _EXPECTED_FILES if not Path(_OUT, f).exists()]
        assert not missing, f"Missing generated files: {missing}"


# ── Class 2: generated_config.h ──────────────────────────────────────────────

class TestGeneratedConfigH:
    """Timing constants, dimension macros, and ECU identity in generated_config.h."""

    def test_p2_timing_value(self):
        _assert_define(_read("generated_config.h"), "GEN_P2_SERVER_MAX_MS", "50U")

    def test_p2_star_timing_value(self):
        _assert_define(_read("generated_config.h"), "GEN_P2_STAR_SERVER_MAX_MS", "5000U")

    def test_s3_timeout_value(self):
        _assert_define(_read("generated_config.h"), "GEN_S3_SERVER_TIMEOUT_MS", "5000U")

    def test_did_count(self):
        _assert_define(_read("generated_config.h"), "GEN_DID_COUNT", "2U")

    def test_dtc_count(self):
        _assert_define(_read("generated_config.h"), "GEN_DTC_COUNT", "1U")

    def test_ecu_name(self):
        c = _read("generated_config.h")
        assert '"TestECU"' in c, f"GEN_ECU_NAME should be \"TestECU\"\n{c[:1000]}"

    def test_ecu_version(self):
        c = _read("generated_config.h")
        assert '"2.0.0"' in c, f"GEN_ECU_VERSION should be \"2.0.0\"\n{c[:1000]}"

    def test_include_guard(self):
        c = _read("generated_config.h")
        assert "#ifndef GENERATED_CONFIG_H" in c
        assert "#define GENERATED_CONFIG_H" in c


# ── Class 3: did_handlers.h ───────────────────────────────────────────────────

class TestDIDHandlersH:
    """Handler count macro, read/write declarations, and absence of spurious write declarations."""

    def test_handler_count_macro(self):
        _assert_define(_read("did_handlers.h"), "GEN_DID_HANDLER_COUNT", "2U")

    def test_read_handler_f190_declared(self):
        assert "did_read_vehicle_identification_number" in _read("did_handlers.h")

    def test_read_handler_f187_declared(self):
        assert "did_read_spare_part_number" in _read("did_handlers.h")

    def test_write_handler_f187_declared(self):
        assert "did_write_spare_part_number" in _read("did_handlers.h")

    def test_no_write_handler_for_read_only_f190(self):
        assert "did_write_vehicle_identification_number" not in _read("did_handlers.h")


# ── Class 4: did_handlers.c ───────────────────────────────────────────────────

class TestDIDHandlersC:
    """DID table entries: decimal IDs, data lengths, access flags, sessions, callbacks."""

    def test_did_f190_decimal_id(self):
        # 0xF190 = 61840
        assert "61840U" in _read("did_handlers.c"), "0xF190 should appear as 61840U"

    def test_did_f187_decimal_id(self):
        # 0xF187 = 61831
        assert "61831U" in _read("did_handlers.c"), "0xF187 should appear as 61831U"

    def test_did_f190_data_length(self):
        assert "(uint16_t)17U" in _read("did_handlers.c")

    def test_did_f187_data_length(self):
        assert "(uint16_t)11U" in _read("did_handlers.c")

    def test_did_f187_read_write_flags(self):
        assert "DID_ACCESS_READ | DID_ACCESS_WRITE" in _read("did_handlers.c")

    def test_did_f190_read_only_exactly_one_write_flag(self):
        # Only the F187 entry has DID_ACCESS_WRITE — F190 must not add another
        assert _read("did_handlers.c").count("DID_ACCESS_WRITE") == 1

    def test_did_f187_extended_session(self):
        assert "UDS_SESSION_EXTENDED" in _read("did_handlers.c")

    def test_did_f190_default_session(self):
        assert "UDS_SESSION_DEFAULT" in _read("did_handlers.c")

    def test_did_f187_write_cb_set(self):
        assert "did_write_spare_part_number" in _read("did_handlers.c")

    def test_did_f190_write_cb_null(self):
        # F190 is the only read-only DID, so write_cb = NULL appears exactly once
        assert _read("did_handlers.c").count(".write_cb           = NULL") == 1


# ── Class 5: uds_init.c — DTC registration ───────────────────────────────────

class TestDTCUDSInit:
    """DTC decimal codes, severity bytes, descriptions, and registration count."""

    def test_dtc_c00100_decimal(self):
        # 0xC00100 = 12*16^5 + 0 + 0 + 1*256 + 0 + 0 = 12582912 + 256 = 12583168
        assert "12583168UL" in _read("uds_init.c"), "0xC00100 should appear as 12583168UL"

    def test_dtc_severity_check_at_next_halt(self):
        # check_at_next_halt encodes as SAE J2012-DA 0x20
        assert "0x20U" in _read("uds_init.c")

    def test_dtc_description_present(self):
        assert '"CAN bus loss"' in _read("uds_init.c")

    def test_single_dtc_registered(self):
        # Count actual call sites only (comment references excluded)
        assert _read("uds_init.c").count("status = dtc_database_register(") == 1

    def test_no_maintenance_only_severity(self):
        # 0x40U is maintenance_only — not in our YAML, must not appear in the DTC section
        assert "0x40U" not in _read("uds_init.c")


# ── Class 6: routine_handlers.c ──────────────────────────────────────────────

class TestRoutineHandlersC:
    """Routine IDs, support flags, sessions, security levels, and results callbacks."""

    def test_routine_ff00_present(self):
        assert "0xFF00" in _read("routine_handlers.c")

    def test_routine_ff01_present(self):
        assert "0xFF01" in _read("routine_handlers.c")

    def test_ff00_start_and_results_flags(self):
        assert "ROUTINE_SUPPORT_START | ROUTINE_SUPPORT_RESULTS" in _read("routine_handlers.c")

    def test_ff01_programming_session(self):
        assert "UDS_SESSION_PROGRAMMING" in _read("routine_handlers.c")

    def test_ff01_start_only_no_results_stub(self):
        # EraseNVM has support: ["start"] only — no results handler should be generated
        assert "routine_results_erasenvm" not in _read("routine_handlers.c")
